lse, "conversation_id_str": "1911262187722821931", "created_at": "Sun Apr 13 03:36:29 +0000 2025", "display_text_range": [0, 279], "entities": {"hashtags": [], "symbols": [], "timestamps": [], "urls": [], "user_mentions": []}, "favorite_count": 52115, "favorited": false, "full_text": "Over the last few months, we've come to a realization that should have landed much harder: NGOs weren't just adjacent to government, they were the parallel government. We were shocked. I was too. But looking back, it's exactly what you'd expect. NGOs operate outside the chain of", "id_str": "1911262187722821931", "is_quote_status": true, "lang": "en", "quote_count": 988, "quoted_status_id_str": "1911254894738047169", "quoted_status_permalink": {"display": "x.com/njeriand/statu…", "expanded": "https://twitter.com/njeriand/status/1911254894738047169", "url": "https://t.co/xNu8jZKDzt"}, "reply_count": 2330, "retweet_count": 16114, "retweeted": false, "user_id_str": "1320917783597625349"}, "note_tweet": {"is_expandable": true, "note_tweet_results": {"result": {"entity_set": {"hashtags": [], "symbols": [], "urls": [], "user_mentions": []}, "id": "Tm90ZVR3ZWV0OjE5MTEyNjIxODc2MDExNjYzMzc=", "media": {"inline_media": []}, "richtext": {"richtext_tags": []}, "text": "Over the last few months, we've come to a realization that should have landed much harder: NGOs weren't just adjacent to government, they were the parallel government. We were shocked. I was too. But looking back, it's exactly what you'd expect. NGOs operate outside the chain of command. They answer to no electorate, no oversight, no public mandate. They can push any agenda they choose without accountability.

So the real question isn't how this happened, or even why. The real question is: why were we surprised? The moment Biden took office, the plan was already in motion. NGOs had the infrastructure, the logistics, the funding pipelines; everything ready to go. They didn't need permission. They just needed power. And when they got it, they had it all set up from day 1: overnight, we were flooded with illegal immigrants under the cover of a coordinated strategy that had been waiting in the wings.

I've been acting like this was some secret operation pulled off behind our backs. But it wasn't. I wasn't deceived; I just failed to see what was right in front of me. Because if you wanted to carry out a bloodless coup, this is exactly how you'd do it."}}}, "quotedRefResult": {"result": {"__typename": "Tweet", "rest_id": "1911254894738047169"}}, "rest_id": "1911262187722821931", "source": "<a href="https://mobile.twitter.com" rel="nofollow">Twitter Web App</a>", "unmention_data": {}, "views": {"count": "56873665", "state": "EnabledWithCount"}}}, "rest_id": "1911424466967572568", "source": "<a href="http://twitter.com/download/iphone" rel="nofollow">Twitter for iPhone</a>", "unmention_data": {}, "views": {"count": "52120006", "state": "EnabledWithCount"}}

